    private async Task<Filters.FilterReuniao?> ProcessFilterVoiceCommandAsync(CommandSpeakerRequest message, Filters.FilterReuniao? existingFilter, string uri)
    {
        try
        {
            // Usar o contexto do FilterReuniaoTXT
            var context = FilterReuniaoTXT.GetPrompt(existingFilter, FilterReuniaoTXT.GetOptions());
            // Instruções específicas para Reuniao
            var additionalInstructions = "";
            // Processar com o serviço genérico
            var filtroProcessado = await _voiceFilterService.ProcessVoiceCommandWithFallbackAsync(message.Message, context, existingFilter, additionalInstructions, uri);
            return filtroProcessado;
        }
        catch (Exception)
        {
            // Se falhar, retornar filtro existente ou novo
            return existingFilter ?? new Filters.FilterReuniao();
        }
    }

